const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
return { json: { token } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
return { json: { ok: true } };

// Sentinel Communications Health — aggregates delivery quality across
// email / SMS / WhatsApp / voice channels over the last 30 days. Reports
// per-channel delivery rate, top failures, bounce + complaint counts,
// unsubscribe + do-not-contact totals, and a 14-day volume trend.
// Also surfaces the latest vendor-health snapshot per channel so live
// vendor degradation shows alongside the trailing 30-day rate.
//
// Data sources:
//   - email_log       (sent_at, status; statuses observed: sent, bounced, complained, dropped, deferred)
//   - messages_sent   (channel, status, error; statuses: sent, delivered, failed, undelivered)
//   - outreach_log    (channel, status, error_message)
//   - leads.unsubscribed / leads.do_not_contact (canonical opt-out flags)
//   - sentinel_vendor_health  (latest 60-min snapshot per vendor, written by vendor-health monitor)
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const emails    = allOf('Email Log 30d');
const messages  = allOf('Messages 30d');
const outreach  = allOf('Outreach 30d');
const unsubs    = allOf('Unsubscribed Leads');
const dnc       = allOf('DNC Leads');
const leadCntRaw= allOf('Lead Count');
const vendorRaw = allOf('Vendor Health Latest');
const spamEvents   = allOf('Spam Events 30d');
const bounceEvents = allOf('Bounce Events 30d');
const totalLeads = (leadCntRaw[0] && leadCntRaw[0].count != null) ? Number(leadCntRaw[0].count) : null;

// Helpers ---------------------------------------------------------
const isFailure = function (status, channel) {
  const s = (status || '').toLowerCase();
  if (!s) return false;
  if (s === 'failed' || s === 'undelivered' || s === 'bounced' || s === 'dropped' || s === 'deferred' || s === 'rejected' || s === 'error') return true;
  return false;
};
const isComplaint = function (status) {
  const s = (status || '').toLowerCase();
  return s === 'complained' || s === 'spam' || s === 'spam_complaint';
};
const isDelivered = function (status) {
  const s = (status || '').toLowerCase();
  return s === 'sent' || s === 'delivered' || s === 'queued' || s === 'success';
};

const now = Date.now();

// Per-channel aggregation -----------------------------------------
const per = { email: empty(), sms: empty(), whatsapp: empty(), voice: empty(), other: empty() };
function empty() { return { sent: 0, delivered: 0, failed: 0, complaints: 0, total: 0 }; }

// Email log
emails.forEach(function (r) {
  if (!r) return;
  per.email.total++;
  if (isFailure(r.status))  per.email.failed++;
  else if (isDelivered(r.status)) per.email.delivered++;
  if (isComplaint(r.status))      per.email.complaints++;
});

// messages_sent — channel-tagged
messages.forEach(function (r) {
  if (!r) return;
  var c = (r.channel || 'other').toLowerCase();
  if (!per[c]) c = 'other';
  per[c].total++;
  if (isFailure(r.status))  per[c].failed++;
  else if (isDelivered(r.status)) per[c].delivered++;
});

// outreach_log — channel-tagged, treat as touches
outreach.forEach(function (r) {
  if (!r) return;
  var c = (r.channel || 'other').toLowerCase();
  if (!per[c]) c = 'other';
  per[c].total++;
  if (isFailure(r.status))  per[c].failed++;
  else if (isDelivered(r.status)) per[c].delivered++;
});

// Compute delivery rate per channel
Object.keys(per).forEach(function (k) {
  var x = per[k];
  x.delivery_rate = x.total > 0 ? Math.round((x.delivered / x.total) * 1000) / 10 : null;
});

// Recent failures across all channels (last 10) -------------------
const failures = [];
emails.forEach(function (r) {
  if (r && isFailure(r.status)) failures.push({ ts: r.sent_at, channel: 'email', recipient: r.recipient || '(unknown)', reason: r.status, subject: r.subject });
});
messages.forEach(function (r) {
  if (r && (isFailure(r.status) || r.error)) failures.push({ ts: r.sent_at, channel: (r.channel || 'other').toLowerCase(), recipient: r.recipient || '(unknown)', reason: r.error || r.status });
});
outreach.forEach(function (r) {
  if (r && (isFailure(r.status) || r.error_message)) failures.push({ ts: r.created_at, channel: (r.channel || 'other').toLowerCase(), recipient: r.lead_id || '(lead)', reason: r.error_message || r.status });
});
failures.sort(function (a, b) { return new Date(b.ts).getTime() - new Date(a.ts).getTime(); });
const recentFailures = failures.slice(0, 10);

// Spam complaints — best effort (Postmark webhook ingestion needed for live tracking)
const spamRecent = emails.filter(function (r) { return r && isComplaint(r.status); })
  .slice(0, 10)
  .map(function (r) { return { ts: r.sent_at, recipient: r.recipient, subject: r.subject }; });

// Volume trend last 14 days per channel ---------------------------
const days = [];
const dayMap = {};
for (var i = 13; i >= 0; i--) {
  var d = new Date(now - i * 86400000);
  var key = d.toISOString().slice(0, 10);
  days.push(key);
  dayMap[key] = { date: key, email: 0, sms: 0, whatsapp: 0, voice: 0 };
}
function bump(ts, channel) {
  if (!ts) return;
  var k = new Date(ts).toISOString().slice(0, 10);
  if (!dayMap[k]) return;
  if (!dayMap[k][channel]) dayMap[k][channel] = 0;
  dayMap[k][channel]++;
}
emails.forEach(function (r)   { bump(r && r.sent_at,    'email'); });
messages.forEach(function (r) { bump(r && r.sent_at,    ((r && r.channel) || 'other').toLowerCase()); });
outreach.forEach(function (r) { bump(r && r.created_at, ((r && r.channel) || 'other').toLowerCase()); });
const trend = days.map(function (k) { return dayMap[k]; });

// Opt-out posture --------------------------------------------------
const optout = {
  unsubscribed: unsubs.length,
  do_not_contact: dnc.length,
  total_leads: totalLeads,
  unsubscribe_rate_pct: (totalLeads && totalLeads > 0) ? Math.round((unsubs.length / totalLeads) * 10000) / 100 : null,
  recent_unsubscribes: unsubs.slice(0, 10).map(function (l) { return { ts: l.unsubscribed_at, name: l.full_name, email: l.email, company: l.company }; })
};

// Vendor health (latest snapshot per vendor over the last 30 min) --
// Rows arrive ordered by measured_at desc, so first-seen per vendor wins.
// We expose two shapes: a flat snapshots[] (for future per-vendor surfaces)
// and a by_channel map keyed by lowercased channel name (for the Comms tab).
const vendorSeen = {};
const vendorSnapshots = [];
let vendorNewestAt = null;
vendorRaw.forEach(function (r) {
  if (!r || !r.vendor) return;
  if (vendorSeen[r.vendor]) return;
  vendorSeen[r.vendor] = true;
  vendorSnapshots.push(r);
  if (!vendorNewestAt || new Date(r.measured_at).getTime() > new Date(vendorNewestAt).getTime()) {
    vendorNewestAt = r.measured_at;
  }
});
const vendorByChannel = {};
vendorSnapshots.forEach(function (r) {
  const c = (r.channel || '').toLowerCase();
  if (!c) return;
  // If two vendors map to the same channel, prefer the worse circuit state.
  const sevRank = { open: 3, half_open: 2, closed: 1 };
  const existing = vendorByChannel[c];
  if (existing && (sevRank[existing.circuit_state] || 0) >= (sevRank[r.circuit_state] || 0)) return;
  vendorByChannel[c] = {
    vendor: r.vendor,
    circuit_state: r.circuit_state,
    failure_rate_pct: r.failure_rate_pct,
    call_count: r.call_count,
    failure_count: r.failure_count,
    last_error: r.last_error,
    measured_at: r.measured_at
  };
});

// Spam + bounce — prefer the live Postmark webhook stream (email_events)
// when it has rows; fall back to the best-effort email_log.status scan so
// the panel still renders before Postmark webhooks are wired up.
const spamFromEvents = spamEvents.filter(function (e) { return e && e.received_at; });
const spamSource = spamFromEvents.length > 0 ? 'postmark_webhook' : 'email_log_scan';
const spamCount = spamFromEvents.length > 0
  ? spamFromEvents.length
  : emails.filter(function (r) { return r && isComplaint(r.status); }).length;
const spamRecentRows = spamFromEvents.length > 0
  ? spamFromEvents.slice(0, 10).map(function (e) { return { ts: e.received_at, recipient: e.recipient, subject: e.subject, tag: e.tag, reason: e.description }; })
  : spamRecent;
const spamNote = spamFromEvents.length > 0
  ? null
  : 'Live spam complaints require Postmark webhook ingestion. Today this column reflects only complaints that landed in email_log.status. Activate the clx-webhook-postmark-events-v1 workflow and point Postmark Server Settings > Webhooks at it to enable live tracking.';

const bounceRows = bounceEvents.filter(function (e) { return e && e.received_at; });
const bounceBySubtype = {};
bounceRows.forEach(function (b) {
  const k = b.bounce_subtype || 'Unknown';
  bounceBySubtype[k] = (bounceBySubtype[k] || 0) + 1;
});
const bounceRecent = bounceRows.slice(0, 10).map(function (b) {
  return { ts: b.received_at, recipient: b.recipient, subject: b.subject, subtype: b.bounce_subtype, reason: b.description };
});

return { json: { ok: true, data: {
  window_days: 30,
  per_channel: per,
  recent_failures: recentFailures,
  spam: {
    complaint_count: spamCount,
    recent: spamRecentRows,
    source: spamSource,
    note: spamNote
  },
  bounces: {
    total: bounceRows.length,
    by_subtype: bounceBySubtype,
    recent: bounceRecent,
    source: bounceRows.length > 0 ? 'postmark_webhook' : 'unavailable'
  },
  opt_out: optout,
  trend_14d: trend,
  vendor_health: {
    by_channel: vendorByChannel,
    snapshots: vendorSnapshots,
    measured_at: vendorNewestAt,
    window_minutes: 60
  }
} } };
